INSERT INTO public.questions (id, exam_id, paper_id, subject_id, chapter_id, question_type, question_text, options, correct_answer, correct_answer_json, auto_gradable, source, is_active, version, source_meta, explanation)
VALUES
  ('social-worker-moex-02581', 'social-worker', 'social-worker-moex-104-d2552697', 'sub-social-worker-06', NULL, 'single_choice', '我國於2001年制定「消除對婦女一切形式歧視公約施行法」，下列條文內容描述，何者錯誤？', '["公約所揭示保障性別人權及促進性別平等之規定，具有國內法律之效力", "政府應依公約規定，建立消除對婦女一切形式歧視報告制度，每2年提出國家報告", "各級政府機關執行公約保障各項性別人權規定所需之經費，應依財政狀況優先編列", "各級政府機關應依公約規定之內容，檢討所主管之法規及行政措施，有不符公約規定者，應於本法施 行後3年內，完成法規之制（訂）定、修正或廢止及行政措施之改進"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:13+00:00", "source_pdf_sha1": "61d6764899ef", "answer_pdf_sha1": "8f599724e6cb", "source_family": "moex-gov-tw", "moex": {"exam_code": "104030", "c": "110", "s": "0604", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會政策與社會立法", "year": "104", "exam_name": "104年第一次專技醫師中醫師分階段考試、中醫師營養師心理師護理師社會工作師考試", "original_question_number": 15, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-02582', 'social-worker', 'social-worker-moex-104-d2552697', 'sub-social-worker-06', NULL, 'single_choice', '行政院於2004年制定「家庭政策」，下列何者不是我國家庭政策制定的原則？', '["充權家內與家庭間的弱勢者", "尊重傳統家庭價值", "公平照顧家庭成員的福祉，並兼顧差別正義的原則", "促進家庭的整合"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:13+00:00", "source_pdf_sha1": "61d6764899ef", "answer_pdf_sha1": "8f599724e6cb", "source_family": "moex-gov-tw", "moex": {"exam_code": "104030", "c": "110", "s": "0604", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會政策與社會立法", "year": "104", "exam_name": "104年第一次專技醫師中醫師分階段考試、中醫師營養師心理師護理師社會工作師考試", "original_question_number": 16, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-02583', 'social-worker', 'social-worker-moex-104-d2552697', 'sub-social-worker-06', NULL, 'single_choice', '我國為配合實施聯合國在2006年身心障礙者權利公約，特別制定「身心障礙者權利公約施行法」，其條 文共12條，下列所述何者錯誤？', '["公約所揭示保障身心障礙者人權之規定，具有國內法律之效力", "行政院為推動本公約相關工作，應邀集學者專家、身心障礙團體（機構）及各政府機關代表成立身心 障礙者權益推動小組。而前項學者專家、身心障礙團體（機構）之人數不得少於總數二分之一，任一 性別不得少於三分之一", "政府應依公約規定建立身心障礙者權利報告制度，於本法施行後2年提出初次國家報告，之後每5年 提出國家報告", "各級政府機關應依公約規定之內容，就其所主管之法規及行政措施於本法實施後 2 年內提出優先檢視 清單"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:13+00:00", "source_pdf_sha1": "61d6764899ef", "answer_pdf_sha1": "8f599724e6cb", "source_family": "moex-gov-tw", "moex": {"exam_code": "104030", "c": "110", "s": "0604", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會政策與社會立法", "year": "104", "exam_name": "104年第一次專技醫師中醫師分階段考試、中醫師營養師心理師護理師社會工作師考試", "original_question_number": 17, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-02584', 'social-worker', 'social-worker-moex-104-d2552697', 'sub-social-worker-06', NULL, 'single_choice', '針對人口老化問題並為提升老人之健康促進與社會參與。行政院曾於2009年9月核定「友善關懷老人服 務方案」，並自2014年1月起推動該方案第二期計畫。此計畫訂有五大目標，下列何者不是目標之一？', '["提倡預防保健、促進健康老化", "建置友善環境、促進在地老化", "引進民間投入、促進活力老化", "鼓勵終身學習、促進樂學老化"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:13+00:00", "source_pdf_sha1": "61d6764899ef", "answer_pdf_sha1": "8f599724e6cb", "source_family": "moex-gov-tw", "moex": {"exam_code": "104030", "c": "110", "s": "0604", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會政策與社會立法", "year": "104", "exam_name": "104年第一次專技醫師中醫師分階段考試、中醫師營養師心理師護理師社會工作師考試", "original_question_number": 18, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-02585', 'social-worker', 'social-worker-moex-104-d2552697', 'sub-social-worker-06', NULL, 'single_choice', '為響應聯合國「國際女童日」精神，重視投資及培力女孩，讓女孩獲得應有的人權與照顧，我國將每年 幾月幾日訂為「臺灣女孩日」？', '["4月2日", "4月4日", "10月11日", "12月5日"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:13+00:00", "source_pdf_sha1": "61d6764899ef", "answer_pdf_sha1": "8f599724e6cb", "source_family": "moex-gov-tw", "moex": {"exam_code": "104030", "c": "110", "s": "0604", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會政策與社會立法", "year": "104", "exam_name": "104年第一次專技醫師中醫師分階段考試、中醫師營養師心理師護理師社會工作師考試", "original_question_number": 19, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-02586', 'social-worker', 'social-worker-moex-104-d2552697', 'sub-social-worker-06', NULL, 'single_choice', '面對人口老化的問題，世界衛生組織（WHO）在2007年提出高齡友善城市的理念及建設，請問此高齡友 善城市的框架乃植基於下列何種概念而成？', '["在地老化", "友善老化", "健康老化", "活躍老化"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:13+00:00", "source_pdf_sha1": "61d6764899ef", "answer_pdf_sha1": "8f599724e6cb", "source_family": "moex-gov-tw", "moex": {"exam_code": "104030", "c": "110", "s": "0604", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會政策與社會立法", "year": "104", "exam_name": "104年第一次專技醫師中醫師分階段考試、中醫師營養師心理師護理師社會工作師考試", "original_question_number": 20, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-02587', 'social-worker', 'social-worker-moex-104-d2552697', 'sub-social-worker-06', NULL, 'single_choice', '根據老人福利法，有關「生活津貼」與「特別照顧津貼」之規定，下列陳述何者正確？', '["生活津貼為普及性給付，凡年滿65歲以上之公民皆有資格領取", "生活津貼的領取資格排除已接受收容安置之老人", "特別照顧津貼為選擇性給付，其家庭必須具備低收入戶身分才有資格領取", "特別照顧津貼限定在失能程度評估為重度、且由家人照顧的老人，該給付由老人領取"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:13+00:00", "source_pdf_sha1": "61d6764899ef", "answer_pdf_sha1": "8f599724e6cb", "source_family": "moex-gov-tw", "moex": {"exam_code": "104030", "c": "110", "s": "0604", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會政策與社會立法", "year": "104", "exam_name": "104年第一次專技醫師中醫師分階段考試、中醫師營養師心理師護理師社會工作師考試", "original_question_number": 21, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-02588', 'social-worker', 'social-worker-moex-104-d2552697', 'sub-social-worker-06', NULL, 'single_choice', '根據兒童及少年福利與權益保障法，下列關於收出養規定的陳述，何者錯誤？', '["從事收出養媒合服務，以經主管機關許可之財團法人、公私立兒童及少年安置、教養機構為限", "收出養媒合服務者從事收出養服務，得向收養人收取費用", "凡父母欲出養兒童及少年，包括親屬之間或繼父母對繼子女間的收出養，均須委託並通過收出養媒合 服務者的評估", "父母對於兒童及少年出養之意見不一致時，父母之一方可以向法院聲請認可"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:13+00:00", "source_pdf_sha1": "61d6764899ef", "answer_pdf_sha1": "8f599724e6cb", "source_family": "moex-gov-tw", "moex": {"exam_code": "104030", "c": "110", "s": "0604", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會政策與社會立法", "year": "104", "exam_name": "104年第一次專技醫師中醫師分階段考試、中醫師營養師心理師護理師社會工作師考試", "original_question_number": 22, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-02589', 'social-worker', 'social-worker-moex-104-d2552697', 'sub-social-worker-06', NULL, 'single_choice', '根據身心障礙者權益保障法，有關身心障礙者之身分鑑定與需求評估，下列陳述何者正確？', '["該法所稱身心障礙者係指身體系統構造或功能，有損傷或不全導致顯著偏離或喪失，影響其活動與參 與社會生活，經醫療專業人員鑑定及評估，領有身心障礙證明者", "身心障礙證明最長期限為3年", "主管機關取得衛生主管機關核轉之身心障礙鑑定報告後，需籌組專業團隊進行需求評估", "各級主管機關與目的事業單位需依服務需求評估之結果，提供身心障礙者無差別性與一致化的服務"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:13+00:00", "source_pdf_sha1": "61d6764899ef", "answer_pdf_sha1": "8f599724e6cb", "source_family": "moex-gov-tw", "moex": {"exam_code": "104030", "c": "110", "s": "0604", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會政策與社會立法", "year": "104", "exam_name": "104年第一次專技醫師中醫師分階段考試、中醫師營養師心理師護理師社會工作師考試", "original_question_number": 23, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-02590', 'social-worker', 'social-worker-moex-104-d2552697', 'sub-social-worker-06', NULL, 'single_choice', '家庭暴力防治法規定某些人員在執行職務時知有疑似家庭暴力情事者，應在24小時內通報當地主管機關。 請問：下列那一類人員並未被賦予上述的通報責任？', '["學校老師", "里長", "社會工作人員", "保育人員"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:13+00:00", "source_pdf_sha1": "61d6764899ef", "answer_pdf_sha1": "8f599724e6cb", "source_family": "moex-gov-tw", "moex": {"exam_code": "104030", "c": "110", "s": "0604", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會政策與社會立法", "year": "104", "exam_name": "104年第一次專技醫師中醫師分階段考試、中醫師營養師心理師護理師社會工作師考試", "original_question_number": 24, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL)
